const auth = $input.first().json.headers?.authorization || '';
const token = process.env.N8N_WEBHOOK_TOKEN_CAPTION || '';
if (!token) throw new Error('Env var N8N_WEBHOOK_TOKEN_CAPTION is not set');
if (auth !== 'Bearer ' + token) {
  throw new Error('Unauthorized: invalid or missing Bearer token');
}
return $input.all();
